  OpenYmin(): void;
  /** The Box will be infinitely long in the Ymax direction. */
  OpenYmax(): void;
  /** The Box will be infinitely long in the Zmin direction. */
  OpenZmin(): void;
  /** The Box will be infinitely long in the Zmax direction. */
  OpenZmax(): void;
